create table awh_main.awh_log (
    log_lfd_nr    number default to_number(sys_guid(), 'XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX'),
    log_table     varchar2(100 byte) not null enable,
    log_col1_val  varchar2(4000 byte),
    log_col2_val  varchar2(4000 byte),
    log_col3_val  varchar2(4000 byte),
    log_col4_val  varchar2(4000 byte),
    log_col5_val  varchar2(4000 byte),
    log_col6_val  varchar2(4000 byte),
    log_col7_val  varchar2(4000 byte),
    log_col8_val  varchar2(4000 byte),
    log_col9_val  varchar2(4000 byte),
    log_col10_val varchar2(4000 byte),
    log_col11_val varchar2(4000 byte),
    log_col12_val varchar2(4000 byte),
    log_col13_val varchar2(4000 byte),
    log_col14_val varchar2(4000 byte),
    log_col15_val varchar2(4000 byte),
    log_col16_val varchar2(4000 byte),
    log_col17_val varchar2(4000 byte),
    log_col18_val varchar2(4000 byte),
    log_col19_val varchar2(4000 byte),
    log_col20_val varchar2(4000 byte),
    log_col21_val varchar2(4000 byte),
    log_col22_val varchar2(4000 byte),
    log_col23_val varchar2(4000 byte),
    log_col24_val varchar2(4000 byte),
    log_col25_val varchar2(4000 byte),
    log_col26_val varchar2(4000 byte),
    log_col27_val varchar2(4000 byte),
    log_col28_val varchar2(4000 byte),
    log_col29_val varchar2(4000 byte),
    log_col30_val varchar2(4000 byte),
    log_timestamp timestamp(6) not null enable,
    log_user      varchar2(200 byte)
)
no inmemory;

alter table awh_main.awh_log
    add constraint awh_log_pk primary key ( log_lfd_nr )
        using index enable;


